#!/bin/sh
# cargo-loco-generate-scaffold/generate.sh
#
# Generator script for Loco scaffolding.
#
# Run from inside a fresh Loco project (one created via
# `loco new --name <form-slug> --db postgres --bg async --assets serverside`)
# to scaffold every CRUD resource for this form. Tables are scaffolded in the
# same order as the form's sql-migrations/ so that FK targets already exist
# when referencing tables are created.
#
# Generated by bin/generate-cargo-loco-scaffold.py from sql-migrations/*.sql.
# Do not edit by hand — re-run the generator after changing the SQL migrations.

set -euf


echo "Scaffolding bone-marrow-donation-assessment (15 tables)..."

cargo loco generate scaffold patient \
    first_name:string! \
    last_name:string! \
    date_of_birth:date! \
    nhs_number:string^ \
    sex:string! \
    weight_kg:double \
    height_cm:double \
    bmi:double \
    --htmx

cargo loco generate scaffold assessment \
    patient:references \
    status:string! \
    --htmx

cargo loco generate scaffold assessment_demographics \
    assessment:references \
    preferred_name:string! \
    gender_identity:string! \
    ethnicity:string! \
    preferred_language:string! \
    interpreter_required:string! \
    gp_name:string! \
    gp_practice:string! \
    referrer_name:string! \
    referrer_role:string! \
    --htmx

cargo loco generate scaffold assessment_donor_registration_hla_typing \
    assessment:references \
    donor_registry:string! \
    donor_registry_id:string! \
    registration_date:date \
    donation_type:string! \
    recipient_relationship:string! \
    hla_a:string! \
    hla_b:string! \
    hla_c:string! \
    hla_drb1:string! \
    hla_dqb1:string! \
    hla_dpb1:string! \
    hla_match_level:string! \
    crossmatch_result:string! \
    previous_donation:string! \
    previous_donation_details:text! \
    hla_typing_notes:text! \
    --htmx

cargo loco generate scaffold assessment_medical_history \
    assessment:references \
    has_autoimmune_disease:string! \
    autoimmune_details:text! \
    has_malignancy:string! \
    malignancy_details:text! \
    has_cardiovascular_disease:string! \
    cardiovascular_details:text! \
    has_respiratory_disease:string! \
    respiratory_details:text! \
    has_renal_disease:string! \
    renal_details:text! \
    has_hepatic_disease:string! \
    hepatic_details:text! \
    has_bleeding_disorder:string! \
    bleeding_disorder_details:text! \
    has_neurological_condition:string! \
    neurological_details:text! \
    current_medications:text! \
    drug_allergies:text! \
    previous_surgery:string! \
    surgery_details:text! \
    medical_history_notes:text! \
    --htmx

cargo loco generate scaffold assessment_physical_examination \
    assessment:references \
    blood_pressure_systolic:int \
    blood_pressure_diastolic:int \
    heart_rate:int \
    temperature_celsius:double \
    respiratory_rate:int \
    oxygen_saturation:int \
    general_appearance:string! \
    cardiovascular_examination:string! \
    cardiovascular_findings:text! \
    respiratory_examination:string! \
    respiratory_findings:text! \
    abdominal_examination:string! \
    abdominal_findings:text! \
    venous_access_assessment:string! \
    venous_access_notes:text! \
    posterior_iliac_crest_assessment:string! \
    physical_examination_notes:text! \
    --htmx

cargo loco generate scaffold assessment_haematological \
    assessment:references \
    haemoglobin:double \
    white_cell_count:double \
    platelet_count:int \
    neutrophil_count:double \
    lymphocyte_count:double \
    haematocrit:double \
    mcv:double \
    blood_group:string! \
    coagulation_screen:string! \
    coagulation_details:text! \
    ferritin:double \
    creatinine:double \
    liver_function:string! \
    liver_function_details:text! \
    haematological_notes:text! \
    --htmx

cargo loco generate scaffold assessment_infectious_disease_screening \
    assessment:references \
    hiv_status:string! \
    hepatitis_b_surface_antigen:string! \
    hepatitis_b_core_antibody:string! \
    hepatitis_c_antibody:string! \
    htlv_status:string! \
    syphilis_screen:string! \
    cmv_status:string! \
    ebv_status:string! \
    toxoplasma_status:string! \
    tuberculosis_screen:string! \
    recent_travel:string! \
    travel_details:text! \
    recent_infection:string! \
    infection_details:text! \
    vaccination_up_to_date:string! \
    infectious_disease_notes:text! \
    --htmx

cargo loco generate scaffold assessment_anaesthetic \
    assessment:references \
    asa_grade:string! \
    previous_anaesthetic:string! \
    anaesthetic_complications:string! \
    complication_details:text! \
    family_anaesthetic_problems:string! \
    family_problem_details:text! \
    mallampati_score:string! \
    airway_concerns:string! \
    airway_details:text! \
    nil_by_mouth_confirmed:string! \
    smoking_status:string! \
    alcohol_use:string! \
    anaesthetic_plan:string! \
    anaesthetic_notes:text! \
    --htmx

cargo loco generate scaffold assessment_collection_method \
    assessment:references \
    preferred_method:string! \
    recipient_preference:string! \
    final_collection_method:string! \
    gcsf_eligible:string! \
    gcsf_contraindications:text! \
    venous_access_suitable_for_apheresis:string! \
    central_line_required:string! \
    estimated_donor_weight_kg:double \
    target_cd34_dose:double \
    estimated_collection_days:int \
    bone_marrow_harvest_volume_ml:int \
    autologous_blood_donation:string! \
    collection_method_notes:text! \
    --htmx

cargo loco generate scaffold assessment_psychological_readiness \
    assessment:references \
    understands_procedure:string! \
    understands_risks:string! \
    voluntary_decision:string! \
    coercion_concerns:string! \
    coercion_details:text! \
    anxiety_about_procedure:string! \
    previous_psychological_issues:string! \
    psychological_issue_details:text! \
    support_network:string! \
    time_off_work_arranged:string! \
    donor_advocate_consulted:string! \
    willing_to_proceed:string! \
    psychological_readiness_notes:text! \
    --htmx

cargo loco generate scaffold assessment_consent_eligibility \
    assessment:references \
    informed_consent_given:string! \
    consent_form_signed:string! \
    consent_date:date \
    witness_name:string! \
    witness_role:string! \
    information_leaflet_provided:string! \
    questions_answered:string! \
    eligibility_decision:string! \
    eligibility_conditions:text! \
    deferral_reason:text! \
    deferral_duration:string! \
    assessor_name:string! \
    assessor_role:string! \
    assessment_date:date \
    consent_eligibility_notes:text! \
    --htmx

cargo loco generate scaffold grading_result \
    assessment:references \
    eligibility:string! \
    overall_risk_level:string! \
    hla_match_level:string! \
    collection_method:string! \
    graded_at:ts! \
    --htmx

cargo loco generate scaffold grading_fired_rule \
    grading_result:references \
    rule_id:string! \
    category:string! \
    description:text! \
    severity_level:string! \
    --htmx

cargo loco generate scaffold grading_additional_flag \
    grading_result:references \
    flag_id:string! \
    category:string! \
    message:text! \
    priority:string! \
    --htmx

echo "Done."
